mapper.select:
${pagingTop} SELECT br_idx, br_loan_id, br_web_id, br_name, br_content, br_score, br_loca, br_ctrlno, add_date, mod_date FROM BOOK_REVIEW WHERE br_loca = #{br_loca}
AND ${search_type} LIKE '%'||#{search_text}||'%'
ORDER BY br_idx DESC ${pagingBottom}

${pagingTop}
SELECT
	br_idx, br_loan_id, br_web_id, br_content, br_score,
	br_loca, br_ctrlno, add_date, mod_date
FROM
	BOOK_REVIEW
WHERE
	br_loan_id = #{br_loan_id}

AND	br_content LIKE '%'||#{search_text}||'%'


AND (TO_DATE(add_date) >= TO_DATE(#{search_start_date}) AND TO_DATE(add_date) <= TO_DATE(#{search_end_date}))


AND br_loca = #{search_loca}

ORDER BY br_idx DESC
${pagingBottom}

SELECT COUNT(*) FROM BOOK_REVIEW WHERE br_loan_id = #{br_loan_id}
AND br_content LIKE '%'||#{search_text}||'%'
AND (TO_DATE(add_date) >= TO_DATE(#{search_start_date}) AND TO_DATE(add_date) <= TO_DATE(#{search_end_date}))
AND br_loca = #{search_loca}
ORDER BY br_idx DESC
